#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        for(int i=0;i<N;i++){
            for(int j=0;j<N;j++){
                if(j) printf(" ");
                printf("1");
            }
            printf("\n");
        }
        if(T) printf("\n"); // optional blank line between test cases
    }
    return 0;
}

